54	async function fetchJson(method, url, bodyObj) {
55	  const res = await fetch(url, {
56	    method,
57	    headers: bodyObj ? { 'content-type': 'application/json' } : undefined,
58	    body: bodyObj ? JSON.stringify(bodyObj) : undefined,
59	  });
60	  const text = await res.text();
61	  let json;
62	  try {
63	    json = JSON.parse(text);
64	  } catch {
65	    json = { raw: text };
66	  }
67	  if (!res.ok) {
68	    console.error(JSON.stringify({ status: res.status, body: json }, null, 2));
69	    process.exit(1);
70	  }
71	  return json;
72	}
