119	function parsePosTriple(s) {
120	  if (!s) {
121	    console.error('--pos x,y,z required');
122	    process.exit(1);
123	  }
124	  const parts = String(s)
125	    .split(',')
126	    .map((t) => Number(t.trim()));
127	  if (parts.length !== 3 || parts.some((n) => !Number.isFinite(n))) {
128	    console.error(`Invalid --pos value: '${s}'. Expected three comma-separated numbers (mm).`);
129	    process.exit(1);
130	  }
131	  return { xMm: parts[0], yMm: parts[1], zMm: parts[2] };
132	}
