159	async function cmdLinksList(modelId) {
160	  const snap = await fetchJson(
161	    'GET',
162	    `${base}/api/models/${encodeURIComponent(modelId)}/snapshot`,
163	  );
164	  const els = snap.elements && typeof snap.elements === 'object' ? snap.elements : {};
165	  const sourceRevisions =
166	    snap.linkSourceRevisions && typeof snap.linkSourceRevisions === 'object'
167	      ? snap.linkSourceRevisions
168	      : {};
169	  const rows = [];
170	  for (const id of Object.keys(els)) {
171	    const row = els[id];
172	    if (row && typeof row === 'object' && row.kind === 'link_model') {
173	      const pinnedRev =
174	        typeof row.sourceModelRevision === 'number' ? row.sourceModelRevision : null;
175	      const currentRev =
176	        typeof sourceRevisions[row.sourceModelId] === 'number'
177	          ? sourceRevisions[row.sourceModelId]
178	          : null;
179	      const drift =
180	        pinnedRev != null && currentRev != null ? Math.max(0, currentRev - pinnedRev) : 0;
181	      rows.push({
182	        linkId: id,
183	        name: row.name ?? null,
184	        sourceModelId: row.sourceModelId ?? null,
185	        positionMm: row.positionMm ?? null,
186	        originAlignmentMode: row.originAlignmentMode ?? 'origin_to_origin',
187	        visibilityMode: row.visibilityMode ?? 'host_view',
188	        hidden: !!row.hidden,
189	        pinned: pinnedRev != null,
190	        pinnedRevision: pinnedRev,
191	        currentSourceRevision: currentRev,
192	        driftCount: drift,
193	      });
194	    }
195	  }
196	  console.log(JSON.stringify({ modelId, links: rows }, null, 2));
