609	async function cmdAgentLoop(modelId, goalPath, maxIter, evidenceOut, backendOverride) {
610	  if (!modelId) {
611	    console.error('agent-loop requires BIM_AI_MODEL_ID');
612	    process.exit(1);
613	  }
614	  if (!goalPath) {
615	    console.error('agent-loop requires --goal <path>');
616	    process.exit(1);
617	  }
618	  const goalText = await readGoalText(goalPath);
619	  await fs.mkdir(evidenceOut, { recursive: true });
620	
621	  let lastScore = -Infinity;
622	  for (let iter = 1; iter <= maxIter; iter++) {
623	    const iterDir = path.join(evidenceOut, `iter-${String(iter).padStart(2, '0')}`);
624	    await fs.mkdir(iterDir, { recursive: true });
625	
626	    const snap = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/snapshot`);
627	    const val = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/validate`);
628	    const evidence = {
629	      revision: snap.revision ?? null,
630	      elementCount: snap.elements ? Object.keys(snap.elements).length : 0,
631	      validate: summariseValidate(val),
632	    };
633	    await fs.writeFile(path.join(iterDir, 'snapshot.json'), JSON.stringify(snap, null, 2));
634	    await fs.writeFile(path.join(iterDir, 'validate.json'), JSON.stringify(val, null, 2));
635	    await fs.writeFile(path.join(iterDir, 'evidence.json'), JSON.stringify(evidence, null, 2));
636	
637	    const baselineScore = progressScore(goalText, snap, val);
638	
639	    const patchResp = await agentIterate(modelId, goalText, snap, val, evidence, iter, backendOverride);
640	    await fs.writeFile(path.join(iterDir, 'patch.json'), JSON.stringify(patchResp, null, 2));
641	
642	    const commands = Array.isArray(patchResp.patch) ? patchResp.patch : [];
643	    if (!commands.length) {
644	      const status = {
645	        status: 'no-patch',
646	        iteration: iter,
647	        rationale: patchResp.rationale ?? '',
648	        confidence: patchResp.confidence ?? 0,
649	      };
650	      await fs.writeFile(path.join(iterDir, 'status.json'), JSON.stringify(status, null, 2));
651	      console.log(JSON.stringify({ ok: true, iteration: iter, status: 'no-patch' }, null, 2));
652	      return;
653	    }
654	
655	    const dryUrl = `${base}/api/models/${encodeURIComponent(modelId)}/commands/bundle/dry-run`;
656	    const dryResp = await fetch(dryUrl, {
657	      method: 'POST',
658	      headers: { 'content-type': 'application/json' },
659	      body: JSON.stringify({ commands, userId: 'agent-loop' }),
660	    });
661	    const dryText = await dryResp.text();
662	    let dryJson;
663	    try {
664	      dryJson = JSON.parse(dryText);
665	    } catch {
666	      dryJson = { raw: dryText };
667	    }
668	    await fs.writeFile(path.join(iterDir, 'dry-run.json'), JSON.stringify(dryJson, null, 2));
669	    if (!dryResp.ok) {
670	      const status = { status: 'dry-run-failed', iteration: iter, body: dryJson };
671	      await fs.writeFile(path.join(iterDir, 'status.json'), JSON.stringify(status, null, 2));
672	      console.log(JSON.stringify({ ok: false, iteration: iter, status: 'dry-run-failed' }, null, 2));
673	      return;
674	    }
675	
676	    const applyResp = await fetchJson(
677	      'POST',
678	      `${base}/api/models/${encodeURIComponent(modelId)}/commands/bundle`,
679	      { commands, userId: 'agent-loop' },
680	    );
681	    await fs.writeFile(path.join(iterDir, 'apply.json'), JSON.stringify(applyResp, null, 2));
682	
683	    const snap2 = await fetchJson(
684	      'GET',
685	      `${base}/api/models/${encodeURIComponent(modelId)}/snapshot`,
686	    );
687	    const val2 = await fetchJson(
688	      'GET',
689	      `${base}/api/models/${encodeURIComponent(modelId)}/validate`,
690	    );
691	    await fs.writeFile(path.join(iterDir, 'snapshot.after.json'), JSON.stringify(snap2, null, 2));
692	    await fs.writeFile(path.join(iterDir, 'validate.after.json'), JSON.stringify(val2, null, 2));
693	
694	    const newScore = progressScore(goalText, snap2, val2);
695	    const progressed = newScore > Math.max(baselineScore, lastScore);
696	    const regressed = newScore < baselineScore;
697	
698	    const status = {
699	      status: progressed ? 'progress' : regressed ? 'regression-rolled-back' : 'no-progress',
700	      iteration: iter,
701	      baselineScore,
702	      newScore,
703	      rationale: patchResp.rationale ?? '',
704	      confidence: patchResp.confidence ?? 0,
705	      patchSize: commands.length,
706	    };
707	    await fs.writeFile(path.join(iterDir, 'status.json'), JSON.stringify(status, null, 2));
708	
709	    if (regressed) {
710	      try {
711	        const undoResp = await fetchJson(
712	          'POST',
713	          `${base}/api/models/${encodeURIComponent(modelId)}/undo`,
714	          { userId: 'agent-loop' },
715	        );
716	        await fs.writeFile(path.join(iterDir, 'undo.json'), JSON.stringify(undoResp, null, 2));
717	      } catch (e) {
718	        await fs.writeFile(
719	          path.join(iterDir, 'undo.error'),
720	          e instanceof Error ? e.message : String(e),
721	        );
722	      }
723	      console.log(JSON.stringify({ ok: false, iteration: iter, status: status.status }, null, 2));
724	      return;
725	    }
726	
727	    if (!progressed) {
728	      console.log(JSON.stringify({ ok: false, iteration: iter, status: status.status }, null, 2));
729	      return;
730	    }
731	
732	    lastScore = newScore;
733	    if (status.status === 'progress' && newScore >= 0 && commands.length === 0) {
734	      // unreachable but kept for clarity
735	      break;
736	    }
737	  }
738	  console.log(
739	    JSON.stringify({ ok: true, iteration: maxIter, status: 'max-iter-reached' }, null, 2),
740	  );
741	}
